INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-10ced7e2-moex-00256', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '社會秩序維護法第80條第1項第1款就意圖得利與人姦、宿者，處3日以下拘留或新臺幣3萬元以下罰鍰 之規定，司法院釋字第666號解釋是以何種理由宣告違憲？', '["性交易行為仍屬憲法第22條所保障之基本權利，立法者不得以善良風俗為由禁止", "以主觀上有無意圖得利，作為是否處罰之差別待遇標準，與立法目的欠缺實質關聯，違反平等原則", "就迫於社會經濟弱勢而從事性交易之女性，處以拘留或罰鍰之行政罰，已逾越必要程度，違反比例 原則", "人民用以謀生的經濟活動，都受憲法職業自由的同等保障，系爭規定侵害性交易服務者的工作權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00257', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於憲法中所規定人民的義務，下列敘述何者錯誤？', '["人民有依法律納稅之義務，即「租稅法定主義」", "人民有依法律服兵役之義務，立法者可於兵役法中規定女子亦須服兵役", "憲法規定之受國民教育義務包括高級中等教育", "人民有受國民教育的義務，而此亦屬人民的權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00258', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '姓名條例規定，命名文字字義粗俗不雅，得申請改名，此係基於保障人民之何種基本權利？', '["人性尊嚴", "人格權", "隱私權", "資訊自主權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00259', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據憲法學理與實務見解，人民主張下列何種行為侵害其基本權利時，司法院大法官或憲法法庭得予 受理？', '["不利確定終局裁判所適用之桃園市自治條例", "不利確定終局裁判所適用之桃園地方法院有罪判決", "不利確定終局裁判所適用之桃園地方法院無罪判決", "不利確定終局裁判未適用之桃園市自治規則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00260', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據司法院大法官解釋，下列敘述何者錯誤？', '["根據釋字第791號解釋，關於撤回通姦罪告訴效力不及於相姦人之差別待遇，是否符合平等權保障， 手段與立法目的間採實質關聯基準", "根據釋字第791號解釋，關於性自主權與個人人格有不可分離關係之限制規範，是否合於比例原則， 適用較為嚴格之審查基準", "根據釋字第767號解釋，關於社會補償之立法，採取中度之審查基準", "根據釋字第799號解釋，對性侵害受處分人之人身自由予以限制，是否違反比例原則，採嚴格審查 標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00261', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於行政機關之組織，下列敘述何者非憲法之明文規定？', '["行政院之組織，應以法律定之", "應以行政院為行政層級中之最高行政機關", "立法院不得於作用法中規定具組織法性質之規範", "行政院所屬各級機關之設置與組織，立法院得以準則性法律，為框架性規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00262', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '下列何者非屬司法機關？', '["懲戒法院之職務法庭", "少年及家事法院", "公務人員保障暨培訓委員會", "司法院大法官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00263', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '基於住民自治之理念與垂直分權之功能，下列敘述何者錯誤？', '["地方自治團體設有地方行政機關及立法機關", "地方自治團體首長與民意代表均由自治區域內之人民依法選舉產生", "地方立法機關議決之預算拘束地方行政機關，地方行政機關不得提出覆議", "中央政府對地方自治團體依法得依事件之性質為適法性或適當性監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00264', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '下列關於「原住民族地區」的敘述，何者錯誤？', '["我國於90年10月31日公布施行之原住民族工作權保障法，規定「原住民地區」中之各級政府機 關、公立學校及公營事業機構，其僱用特定人員之總額中，原住民的人數應達一定比例之門檻", "原住民族委員會於民國91年報請行政院核定30個山地鄉及25個平地鄉（鎮、市）為原住民地區", "我國於94年2月5日公布施行之原住民族基本法中，對於「原住民族地區」之定義，乃沿用原住 民族工作權保障法之規定，亦即「原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原 住民族主管機關報請行政院核定之地區」。至於「原住民族地區」之具體範圍，則承襲民國91年行 政院所核定之「原住民地區」範圍", "原住民族基本法中，對於部落之定義，亦和「原住民族地區」有關，其「係指原住民於原住民族 地區一定區域內，依其傳統規範共同生活結合而成之團體，經中央原住民族主管機關報請行政院 核定者」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00265', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '民國110年9月，最高法院作成第108年度台上大字第1636號裁定（併案：109年度台上字第1302 號及110年度台上字第709號），對於非原住民透過借名登記，取得原住民保留地使用之情形，裁定 借名登記、買賣契約違反民法第71條本文規定，應屬無效。下列何者非屬本裁定所採取的理由？', '["憲法增修條文第10條第12項，即已揭示國家應保障原住民族之地位，對其經濟土地予以保障扶助 並促其發展", "山坡地保育利用條例第37條，以及原住民保留地開發管理辦法第18條，都明訂原住民取得原住民 保留地所有權後，除政府指定之特定用途外，其移轉之承受人以原住民為限", "民法第71條本文規定，法律行為違反強制或禁止之規定者，無效。非原住民藉法律行為以規避山 坡地保育利用條例第37條、原住民保留地開發管理辦法第18條之禁止規定，悖於保護原住民族意 旨，該法律行為應屬無效", "原住民族基本法第20條明訂，政府承認原住民族土地及自然資源權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL)
